UPDATE public.questions SET
  stimulus_text = 'A group of students are preparing a presentation on the history of the United States. They want to include a section on the American Revolution, and they’ve written the following sentence in their script: “The American Revolution was a complex period in which many changes occurred, such as the formation of a new government and the adoption of a new constitution.”',
  question_text = 'Which of the following revisions of the sentence above is the most effective?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The American Revolution was a complex period in which many changes occurred—for example, the formation of a new government and the adoption of a new constitution.","is_correct":true,"explanation":"Choice A is the most effective revision of the sentence. It uses the correct punctuation for an appositive phrase, which is a phrase that renames a noun or pronoun. The other choices either use incorrect punctuation or make the sentence unnecessarily wordy. Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The American Revolution was a complex period, in which many changes occurred, such as the formation of a new government and the adoption of a new constitution.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The American Revolution was a complex period, with many changes, including the formation of a new government and the adoption of a new constitution.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The American Revolution was a complex period, because many changes occurred, such as the formation of a new government and the adoption of a new constitution.","is_correct":false,"explanatio